    ctx.fillText("R\u00b2 = "+sig3(active.r2),pd.left+cw2-12,pd.top+18);
    ctx.textAlign="left";
    ctx.fillStyle="#556682";
    ctx.font="600 13px -apple-system,system-ui,sans-serif";
