    res.forEach(function(p,pi){p.samps.forEach(function(s,si){var sl=gsc(pi,si);c+=(pi+1)+',"'+s.name+'",'+sm+','+(sl&&sl.dil!=null?sl.dil:"")+","+(sl&&sl.cv!=null?(sl.cv*100).toFixed(1):"")+","+(sl&&sl.conc!=null?sig3(sl.conc):"")+","+p.sc.r2.toFixed(5)+"\n";});});
