      setCfg({sn:"GFP",sc:"1",sdf:"1/10",sds:"1/2",xdf:"1/10",xds:"1/2",np:"1",tp:"no",at:"direct",fm:"linear",names:"SS\nSS spike\nTT",sr:"2",xr:"2",unit:"mg/mL",target:"GFP",tmpl:"bca",spikeUsed:"no",layout:"transposed"});
